	fmt.Fprintf(logFile, "APNs Token ID: %s\n", apnsTokenID)

	log.Printf("Results written to /home/user/myproject/output.log")
	log.Printf("Web Push Token ID: %s", webPushTokenID)
	log.Printf("APNs Token ID: %s", apnsTokenID)
}

