package handlers

import (
	"github.com/magicbell/magicbell-go/pkg/project-client/internal/clients/rest/httptransport"
)

// Handler defines the interface for request processing in the handler chain.
// Each handler can process both regular and streaming requests.
// T is the response type, E is the error type.
type Handler[T any, E any] interface {
	Handle(req httptransport.Request) (*httptransport.Response[T], *httptransport.ErrorResponse[E])
	HandleStream(req httptransport.Request) (*httptransport.Stream[T], *httptransport.ErrorResponse[E])
	SetNext(handler Handler[T, E])
}

// HandlerChain manages a chain of handlers for processing requests.
// Implements the chain of responsibility pattern for request/response processing.
type HandlerChain[T any, E any] struct {
	head Handler[T, E]
	tail Handler[T, E]
}

// BuildHandlerChain creates a new empty handler chain.
// Handlers can be added using AddHandler to build the processing pipeline.
func BuildHandlerChain[T any, E any]() *HandlerChain[T, E] {
	return &HandlerChain[T, E]{}
}

// AddHandler appends a handler to the end of the chain.
// Returns the chain for method chaining. Handlers execute in the order they are added.
func (chain *HandlerChain[T, E]) AddHandler(handler Handler[T, E]) *HandlerChain[T, E] {
	if chain.head == nil {
		chain.head = handler
		chain.tail = handler
		return chain
	}

	chain.tail.SetNext(handler)
	chain.tail = handler

	return chain
}

// CallApi processes a regular HTTP request through the handler chain.
// Returns the processed response or an error response.
func (chain *HandlerChain[T, E]) CallApi(request httptransport.Request) (*httptransport.Response[T], *httptransport.ErrorResponse[E]) {
	return chain.head.Handle(request)
}

// StreamApi processes a streaming HTTP request through the handler chain.
// Returns a stream for consuming response chunks or an error response.
func (chain *HandlerChain[T, E]) StreamApi(request httptransport.Request) (*httptransport.Stream[T], *httptransport.ErrorResponse[E]) {
	return chain.head.HandleStream(request)
}

package rest

import (
	"github.com/magicbell/magicbell-go/pkg/project-client/internal/clients/rest/handlers"
	"github.com/magicbell/magicbell-go/pkg/project-client/internal/clients/rest/hooks"
	"github.com/magicbell/magicbell-go/pkg/project-client/internal/clients/rest/httptransport"
	"github.com/magicbell/magicbell-go/pkg/project-client/clientconfig"
)

// RestClient is a generic HTTP client that handles API requests through a chain of handlers.
// It supports both regular and streaming requests with type-safe response handling.
// T is the response type, E is the error type.
type RestClient[T any, E any] struct {
	handlers *handlers.HandlerChain[T, E]
}

// NewRestClient creates a new REST client with the configured handler chain.
// Initializes all handlers in the correct order for request processing.
func NewRestClient[T any, E any](config clientconfig.Config, hook hooks.Hook) *RestClient[T, E] {
	retryHandler := handlers.NewRetryHandler[T, E]()
	bearerTokenHandler := handlers.NewAccessTokenHandler[T, E]()
	responseValidationHandler := handlers.NewResponseValidationHandler[T, E]()
	unmarshalHandler := handlers.NewUnmarshalHandler[T, E]()
	requestValidationHandler := handlers.NewRequestValidationHandler[T, E]()
	hookHandler := handlers.NewHookHandler[T, E](hook)
	terminatingHandler := handlers.NewTerminatingHandler[T, E]()

	handlers := handlers.BuildHandlerChain[T, E]().
		AddHandler(retryHandler).
		AddHandler(bearerTokenHandler).
		AddHandler(responseValidationHandler).
		AddHandler(unmarshalHandler).
		AddHandler(requestValidationHandler).
		AddHandler(hookHandler).
		AddHandler(terminatingHandler)

	return &RestClient[T, E]{
		handlers: handlers,
	}
}

// Call executes a regular HTTP request through the handler chain.
// Returns the response with deserialized data or an error response.
func (client *RestClient[T, E]) Call(request httptransport.Request) (*httptransport.Response[T], *httptransport.ErrorResponse[E]) {
	return client.handlers.CallApi(request)
}

// Stream executes a streaming HTTP request through the handler chain.
// Returns a stream for consuming response chunks or an error response.
func (client *RestClient[T, E]) Stream(request httptransport.Request) (*httptransport.Stream[T], *httptransport.ErrorResponse[E]) {
	return client.handlers.StreamApi(request)
}

package httptransport

import (
	"bytes"
	"context"
	"fmt"
	"net/http"
	"net/url"
	"reflect"
